I cannot directly generate a 3D image file (like a .obj or .fbx) or render a real-time 3D scene within this chat interface. However, I can provide you with the **complete code** to render a 3D house using **Three.js**, a popular JavaScript library for 3D graphics.

You can run this code immediately in your browser.

### Option 1: Run in Browser (Instant)
Copy the code below, save it as an `.html` file (e.g., `house.html`), and open it in any web browser.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>3D House Render</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">Click & Drag to Rotate | Scroll to Zoom</div>

    <!-- Import Three.js from CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 20);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        // 2. Controls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;

        // 3. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 4. Materials
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0x8B4513 }); // Brown
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0x555555 }); // Grey
        const glassMaterial = new THREE.MeshStandardMaterial({ color: 0xADD8E6, transparent: true, opacity: 0.6 });
        const grassMaterial = new THREE.MeshStandardMaterial({ color: 0x228B22 });

        // 5. Building the House
        const houseGroup = new THREE.Group();

        // Floor
        const floorGeo = new THREE.BoxGeometry(10, 1, 10);
        const floor = new THREE.Mesh(floorGeo, grassMaterial);
        floor.position.y = -0.5;
        floor.receiveShadow = true;
        houseGroup.add(floor);

        // Main Body
        const bodyGeo = new THREE.BoxGeometry(8, 6, 8);
        const body = new THREE.Mesh(bodyGeo, wallMaterial);
        body.position.y = 3;
        body.castShadow = true;
        body.receiveShadow = true;
        houseGroup.add(body);

        // Roof
        const roofGeo = new THREE.ConeGeometry(7, 4, 4);
        const roof = new THREE.Mesh(roofGeo, roofMaterial);
        roof.position.y = 8;
        roof.rotation.y = Math.PI / 4;
        roof.castShadow = true;
        houseGroup.add(roof);

        // Windows
        const windowGeo = new THREE.BoxGeometry(2, 2, 0.2);

        // Front Window
        const win1 = new THREE.Mesh(windowGeo, glassMaterial);
        win1.position.set(0, 4, 4.1);
        houseGroup.add(win1);

        // Side Window
        const win2 = new THREE.Mesh(windowGeo, glassMaterial);
        win2.position.set(4.1, 4, 0);
        houseGroup.add(win2);

        // Door
        const doorGeo = new THREE.BoxGeometry(2, 4, 0.5);
        const door = new THREE.Mesh(doorGeo, new THREE.MeshStandardMaterial({ color: 0x333333 }));
        door.position.set(0, 2, 4.25);
        houseGroup.add(door);

        // Tree (Simple Cone)
        const treeGeo = new THREE.ConeGeometry(2, 6, 8);
        const treeMat = new THREE.MeshStandardMaterial({ color: 0x006400 });
        const tree = new THREE.Mesh(treeGeo, treeMat);
        tree.position.set(-6, 3, -6);
        tree.castShadow = true;
        houseGroup.add(tree);

        // Trunk
        const trunkGeo = new THREE.CylinderGeometry(0.5, 0.5, 2);
        const trunkMat = new THREE.MeshStandardMaterial({ color: 0x8B4513 });
        const trunk = new THREE.Mesh(trunkGeo, trunkMat);
        trunk.position.set(-6, 1, -6);
        houseGroup.add(trunk);

        scene.add(houseGroup);

        // 6. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle Resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### Option 2: Generate via Python (Blender)
If you have Python installed, you can use the `blender` command-line tool to generate a `.blend` file containing a house.

1.  Install Blender.
2.  Run this script in your terminal:

```bash
python -c "
import bpy
bpy.ops.wm.blender_add_file(filepath='path_to_script.py')
"
```

*(Note: For a direct Python script to generate a Blender file without the GUI, you would typically use the `bpy` module directly in a script file `create_house.py` and run `blender --background --python create_house.py`.)*

### How to use the HTML version:
1.  Copy the code block above.
2.  Create a new file on your computer named `house.html`.
3.  Paste the code into that file and save it.
4.  Double-click `house.html` to open it in Chrome, Firefox, or Edge.
5.  **Interact:** Click and drag to rotate the camera, scroll to zoom in/out.
